const events = $input.all();
const now = new Date();
const nowTime = now.getTime();

// Paksa konversi ke Waktu Indonesia Barat (WIB) untuk jam malam
const currentHour = parseInt(now.toLocaleString("en-US", { timeZone: "Asia/Jakarta", hour: "2-digit", hour12: false }));

// Tetap aman menggunakan sintaks $getWorkflowStaticData n8n modern
const staticData = $getWorkflowStaticData('global');

let currentEvent = null;
let upcomingEvent = null;
let totalBusyMinutes = 0;
let completedEvents = []; 

// Membedah seluruh jadwal hari ini
events.forEach(item => {
  const ev = item.json;
  if (!ev.start || !ev.start.dateTime) return;

  // Ganti kode pembersihan lama dengan regex yang lebih agresif ini:
  if (typeof ev.summary === 'string') {
    // Menghapus semua jenis newline, tab, dan spasi berlebih di awal/akhir teks
    ev.summary = ev.summary.replace(/[\r\n\t]+/g, ' ').replace(/\s+/g, ' ').trim();
  }

  // 🔥 FILTER BARU: Abaikan acara jika itu adalah waktu tidur
  const lowerSummary = ev.summary.toLowerCase();
  const isSleepEvent = lowerSummary.includes('tidur') || lowerSummary.includes('sleep') || lowerSummary.includes('istirahat');

  if (isSleepEvent) {
    return; // Hentikan proses untuk acara ini dan lanjut ke acara berikutnya di loop
  }

  const start = new Date(ev.start.dateTime).getTime();
  const end = new Date(ev.end.dateTime).getTime();

  // 1. Akumulasi semua kelas hari ini yang SUDAH DIMULAI (Lalu/Sedang Berjalan)
  if (start <= nowTime) {
    // Jika acara sudah selesai, hitung durasi penuh. Jika sedang berjalan, hitung sampai menit ini.
    const effectiveEnd = Math.min(end, nowTime);
    totalBusyMinutes += (effectiveEnd - start) / (1000 * 60);

    // Masukkan ke daftar agenda yang dikerjakan hari ini
    if (ev.summary && !completedEvents.includes(ev.summary)) {
      completedEvents.push(ev.summary);
    }
  }

  // 2. Deteksi kelas yang SEDANG berjalan saat ini
  if (start <= nowTime && end > nowTime) {
    currentEvent = ev;
  }

  // 3. Deteksi acara mendatang (45 menit)
  if (start > nowTime && start <= nowTime + (360 * 60 * 1000)) {
    upcomingEvent = ev;
  }
});

// --- LOGIKA RUTING & PENGUNCI SPAM ---
if (upcomingEvent) {
  if (staticData.last_upcoming_id !== upcomingEvent.id) {
    staticData.last_upcoming_id = upcomingEvent.id;
    return [{ 
      json: { 
        action: "SEND_REMINDER", 
        title: upcomingEvent.summary, 
        location: upcomingEvent.location || "Kelas", 
        description: upcomingEvent.description || "-",
        // 🔥 OUTPUT BARU: Menyertakan format ISO dateTime untuk dibaca node LLM berikutnya
        start_time: upcomingEvent.start.dateTime 
      } 
    }];
  }
} 
else if (currentEvent) {
  const isQuietHours = currentHour >= 22 || currentHour < 7;
  if (staticData.last_current_id !== currentEvent.id) {
    if (!isQuietHours) {
      staticData.last_current_id = currentEvent.id;
      return [{ 
        json: { 
          action: "AI_CURRENT_ENGAGE", 
          title: currentEvent.summary, 
          description: currentEvent.description || "-",
          // Disertakan juga di sini jika sewaktu-waktu Anda membutuhkannya
          start_time: currentEvent.start.dateTime 
        } 
      }];
    }
  }
} 
else {
  // WAKTU KOSONG (FREE TIME)
  const lastFreeAlert = staticData.last_free_alert_time || 0;
  const hoursSinceLastAlert = (nowTime - lastFreeAlert) / (1000 * 60 * 60);

  if (hoursSinceLastAlert > 2) {
    const isQuietHours = currentHour >= 22 || currentHour < 7;
    if (!isQuietHours) {
      staticData.last_free_alert_time = nowTime;
      return [{ 
        json: { 
          action: "AI_FREE_ENGAGE", 
          is_packed_morning: totalBusyMinutes >= 240, 
          busy_hours: (totalBusyMinutes / 60).toFixed(1), 
          completed_events_text: completedEvents.length > 0 ? completedEvents.join(", ") : "Belum ada agenda" 
        } 
      }];
    }
  }
}

// Hentikan alur jika tidak ada kondisi yang terpenuhi
return [];

