    // 2. Coba parsing jika content berupa string JSON
    const parsedData = JSON.parse(content);

    // Pastikan hasil parsing adalah objek dan bukan null
    if (parsedData && typeof parsedData === 'object') {
        if (Array.isArray(parsedData)) {
            return parsedData.map(item => ({
                json: typeof item === 'object' && item !== null ? item : { data: item }
            }));
        }
        return [{ json: parsedData }];
    }

    // Jika hasil parsing bukan objek (misal: angka atau boolean)
    return [{ json: { data: parsedData } }];

} catch (e) {
    // 3. JIKA CONTENT TEKS BIASA: Pastikan 'json' menunjuk ke objek { text: ... }
    return [{ 
        json: { 
            text: content || "" 
        } 
    }];
