// 1. Ambil semua item dari input
const items = $input.all();
if (items.length === 0) return [];

// 2. Gunakan built-in n8n $now dengan zona waktu Asia/Jakarta
const nowWIB = $now.setZone('Asia/Jakarta').toISO();

// 3. Filter nama aktivitas yang valid (buang null, undefined, atau string kosong)
const validActivities = items
  .map(item => item.json.activity_name)
  .filter(name => name !== null && name !== undefined && name !== "");

// 4. Tentukan opsi dan judul poling berdasarkan kondisi data
let options = [];
let pollTitle = "";

if (validActivities.length === 0) {
  // Kondisi JIKA DATA KOSONG / NULL
  options = ["Buat Habit Baru ✨","Lainnya..."];
  pollTitle = "Waktunya luang nih! tapi belum ada list habit. Mau buat habit baru atau lakukan aktivitas Lain?";
} else {
  // Kondisi JIKA DATA ADA
  options = [...validActivities, "Lainnya..."];
  pollTitle = "Waktunya luang nih! Biar tetap produktif, mau fokus ke mana sekarang?";
}

// 5. Transformasi data untuk output ke node berikutnya
return items.map(item => {
  // Buat objek dasar yang selalu ada (untuk WAHA poling)
  const outputJson = {
    waha_poll_title: pollTitle,
    waha_poll_options: options
  };

  // HANYA tambahkan id, points, dan last_suggested_at jika id valid (tidak null/undefined)
  if (item.json.id !== null && item.json.id !== undefined) {
    outputJson.id = item.json.id;
    outputJson.points = Math.max(0, (item.json.points || 0) - 1);
    outputJson.last_suggested_at = nowWIB;
  }

  return {
    json: outputJson
  };
});

// 1. Proteksi input aman dari null/kosong
const deadlines = $input.all() || [];
let habitItems = [];
try {
  const nodeData = $('Code in JavaScript2').all();
  if (Array.isArray(nodeData)) habitItems = nodeData;
} catch (e) {
  habitItems = []; 
}

const now = new Date();
const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
const maxDate = new Date(todayStart);
maxDate.setDate(todayStart.getDate() + 5); 

let urgentDeadlines = [];
let deadlineText = "";

// 2. Filter deadline 5 hari ke depan
deadlines.forEach(item => {
  if (item?.json) {
    const d = item.json;
    if (d.due_date && d.task_name) {
      const dueDate = new Date(d.due_date);
      if (dueDate >= todayStart && dueDate <= maxDate) {
        urgentDeadlines.push(d);
        const dateStr = dueDate.toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long' });
        deadlineText += `- ${d.task_name} (Batas: ${dateStr})\n`;
      }
    }
  }
});

if (urgentDeadlines.length === 0) {
  deadlineText = "Tidak ada deadline mendesak dalam 5 hari ke depan.";
}

// 3. Set Judul, Opsi, dan Metadata secara Dinamis
let pollTitle = "Waktunya luang nih! Biar tetap produktif, mau fokus ke mana sekarang?";
let pollOptions = [];

// Cek apakah node habit valid, memiliki opsi poling, dan ID-nya tidak null/kosong
const habitJson = habitItems.length > 0 ? habitItems[0].json : null;
const hasValidId = habitJson && habitJson.id !== null && habitJson.id !== undefined && habitJson.id !== "";
const hasHabitData = habitJson && habitJson.waha_poll_options && hasValidId;

let habitMetadata = {};

if (hasHabitData) {
  // Ambil data opsi poling asli jika lolos validasi ID
  pollOptions = [...habitJson.waha_poll_options];

  // Ekstrak metadata
  habitMetadata = {
    id: habitJson.id,
    points: habitJson.points ?? 0,
    last_suggested_at: habitJson.last_suggested_at || new Date().toISOString()
  };
} else {
  // JIKA HABIT KOSONG ATAU ID NYA NULL: Judul alternatif & opsi buat habit baru
  pollTitle = "Belum ada list habit nih! Mau buat habit baru atau lakukan aktivitas ini?";
  pollOptions = [
    "Buat Habit Baru ✨",
    "Lainnya..."
  ];
}

// 4. Sisipkan opsi "Kerjakan Deadline" jika ada yang mendesak
if (urgentDeadlines.length > 0) {
  pollOptions.unshift("Kerjakan Deadline 🚨");
}

;

// 6. Output final (Metadata HANYA muncul jika hasHabitData bernilai true)
return [{ 
  json: { 
    poll_title: pollTitle,
    habit_options_list: pollOptions, 
    deadline_context: deadlineText.trim(), 
    has_urgent_deadline: urgentDeadlines.length > 0,
    ...(hasHabitData ? habitMetadata : {}) // Disembunyikan total jika ID null atau data kosong
  } 
}];
